function ShowLog(){var e="",t="",o=0,a=0;this.start_stop=function(n){var l=$('input[name="autoload"]').prop("checked"),s=Number($('input[name="auto_interval"]').val());if(a=o=s,l&&s<1)return alert(n),!1;if(l){$("#timer").html(a),$("#counter").fadeIn("slow");e=setInterval(this.do_request,1e3*s),t=setInterval(this.start_counter,1e3)}else clearInterval(e),clearInterval(t),$("#timer").val(0),$("#counter").fadeOut("slow")},this.do_request=function(){var e=encodeURIComponent($('select[name="file"]').val()),t=encodeURIComponent($('select[name="page"]').val());jQuery.ajax({data:"file="+e+"&page="+t,url:"request_port.php?module=Log&action=show",type:"POST",async:!0,success:function(e){$("#log_content").html(e)}}).html},this.start_counter=function(){(a-=1)<1&&(a=o),$("#timer").html(a)},this.clear_log=function(){var e=encodeURIComponent($('select[name="file"]').val());jQuery.ajax({data:"file="+e,url:"request_port.php?module=Log&action=clear",type:"POST",async:!1,success:function(e){$("#log_message").html(" - "+e),$("#log_message").fadeIn("slow").delay(2e3).fadeOut("slow")}}).html},this.delete_log=function(){var e=encodeURIComponent($('select[name="file"]').val());jQuery.ajax({data:"file="+e,url:"request_port.php?module=Log&action=delete",type:"POST",async:!0,success:function(e){$("#log_message").html(" - "+e),$("#log_message").fadeIn("slow").delay(2e3).fadeOut("slow")}}).html},this.download_log=function(){var e="request_port.php?module=Log&action=download&file="+encodeURIComponent($('select[name="file"]').val());window.open(e)}}